'use client'

import { useRouter } from 'next/navigation'
import { useEffect, useState } from 'react'
import GovNavbar from '@/components/government/navbar'
import GovProblemCard from '@/components/government/problem-card'
import { Button } from '@/components/ui/button'
import { Empty } from '@/components/ui/empty'
import { Skeleton } from '@/components/ui/skeleton'
import { ArrowLeft } from 'lucide-react'

export default function RecurringPage() {
  const router = useRouter()
  const [problems, setProblems] = useState<any[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    // TODO: Replace with actual API call to fetch recurring problems
    const fetchProblems = async () => {
      try {
        setIsLoading(true)
        // Simulate API delay
        await new Promise(resolve => setTimeout(resolve, 500))
        // TODO: Fetch from /api/problems/recurring or similar
        setProblems([])
      } catch (err) {
        setError('Failed to load recurring problems')
      } finally {
        setIsLoading(false)
      }
    }

    fetchProblems()
  }, [])

  return (
    <div className="min-h-screen bg-background">
      <GovNavbar governmentName="Government Official" />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
        {/* Header with back button */}
        <div className="mb-8">
          <Button
            variant="ghost"
            onClick={() => router.back()}
            className="mb-4 text-muted-foreground hover:text-foreground gap-2"
          >
            <ArrowLeft className="w-4 h-4" />
            Back
          </Button>
          <h1 className="text-3xl font-bold text-foreground mb-2">Recurring Problems</h1>
          <p className="text-muted-foreground">
            Issues detected multiple times across different locations
          </p>
        </div>

        {/* Filters (Optional) */}
        <div className="mb-6 flex flex-wrap gap-2">
          <Button variant="outline" size="sm" className="border-border hover:bg-secondary">
            All Severity
          </Button>
          <Button variant="outline" size="sm" className="border-border hover:bg-secondary">
            High
          </Button>
          <Button variant="outline" size="sm" className="border-border hover:bg-secondary">
            Most Reported
          </Button>
        </div>

        {/* Content */}
        {error ? (
          <Empty
            icon="alert-circle"
            title="Error loading problems"
            description="Failed to load recurring problems. Please try again."
          />
        ) : isLoading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {Array.from({ length: 6 }).map((_, i) => (
              <Skeleton key={i} className="h-56 bg-secondary rounded-lg" />
            ))}
          </div>
        ) : problems.length === 0 ? (
          <Empty
            icon="trending-up"
            title="No recurring problems"
            description="No issues have been reported multiple times"
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {problems.map((problem) => (
              <GovProblemCard
                key={problem.id}
                {...problem}
                type="recurring"
              />
            ))}
          </div>
        )}
      </main>
    </div>
  )
}
